struct Point {
    val x, y, z: Int64

    // Implement equality check for use in Sets
    fn == (other: Point): Bool {
        x == other.x && y == other.y && z == other.z
    }

    // Implement hash function for use in Sets
    // Since coordinates are small (0-6), we can map them to a single unique integer if needed,
    // but standard hashing based on components should suffice for competitive programming constraints.
    // Using a simple combination hash is generally robust enough here.
    fn hash: Int64 {
        // Simple multiplicative hashing based on the coordinates
        (x * 73856093) ^ (y * 19349663) ^ (z * 83492791)
    }
}

// Helper function to convert input array format to Point structure
fn array_to_point(arr: Array(Int64)): Point {
    Point(arr[0], arr[1], arr[2])
}

// Helper function to calculate midpoint
fn calculate_midpoint(a: Point, b: Point): Point {
    Point(
        (a.x + b.x) / 2,
        (a.y + b.y) / 2,
        (a.z + b.z) / 2
    )
}

def solve(points: Array(Array(Int64)), target: Array(Int64)): Int64 {
    // 1. Initialize Sets and Target Point
    var all_points: Set(Point) = Set.new()
    var target_point: Point = array_to_point(target)

    for p_arr in points {
        all_points.add(array_to_point(p_arr))
    }

    // 2. Check k=0
    if all_points.contains(target_point) {
        return 0
    }

    var k: Int64 = 0

    // 3. Simulation loop (BFS style)
    loop do
        k += 1
        var newly_generated_points: Set(Point) = Set.new()
        var points_list: Array(Point) = all_points.to_a()
        var n_points = points_list.size

        // If there are fewer than 2 distinct points, we cannot generate new ones.
        if n_points < 2 {
            return -1
        }

        // Iterate over all unique pairs {a, b} from the current set of all points
        for i in 0 .. n_points - 1 {
            for j in i + 1 .. n_points - 1 {
                var a = points_list[i]
                var b = points_list[j]

                // The rule specifies pairing two DIFFERENT points. Since we ensured i != j,
                // and all_points stores unique coordinate points, a != b is guaranteed.

                var c = calculate_midpoint(a, b)

                // Only consider points that are truly new (not already in the entire set)
                if !all_points.contains(c) {
                    newly_generated_points.add(c)
                }
            }
        }

        // 4. Check if target was generated in this step
        if newly_generated_points.contains(target_point) {
            return k
        }

        // 5. Update the set of all points
        for c in newly_generated_points {
            all_points.add(c)
        }

        // 6. Termination condition: If no new points were generated, we stop.
        if newly_generated_points.size == 0 {
            return -1
        }
    end
}
